from typing import TypedDict, Optional
from langgraph.graph import StateGraph, END

class AgentState(TypedDict):
    query: str
    tier: str
    context: Optional[list[str]]   # from RAG — may be None in reduced tier
    tool_results: Optional[list]   # from tool calls — may be None in reduced tier
    response: str

def assess_tier(state: AgentState) -> dict:
    tier = current_tier(breakers)
    return {"tier": tier.name}

def retrieve_context(state: AgentState) -> dict:
    flags = TIER_FLAGS[ServiceTier[state["tier"]]]
    if not flags.rag_retrieval:
        return {"context": None}   # skip gracefully
    docs = protected_vector_search(state["query"])
    return {"context": [d.page_content for d in docs]}

def call_tools(state: AgentState) -> dict:
    flags = TIER_FLAGS[ServiceTier[state["tier"]]]
    if not flags.tool_calls:
        return {"tool_results": None}
    results = run_tools(state["query"])
    return {"tool_results": results}

def generate_response(state: AgentState) -> dict:
    flags = TIER_FLAGS[ServiceTier[state["tier"]]]
    if not flags.llm_completions:
        return {"response": "Service is temporarily limited. Please try again shortly."}

    context_str = ""
    if state.get("context"):
        context_str = "\nContext:\n" + "\n".join(state["context"])
    tool_str = ""
    if state.get("tool_results"):
        tool_str = "\nTool results: " + str(state["tool_results"])

    prompt = state["query"] + context_str + tool_str
    if state["tier"] == "REDUCED":
        prompt = f"[Operating in reduced mode — answer from knowledge only]\n{prompt}"

    response = protected_completion(prompt)
    return {"response": response}

builder = StateGraph(AgentState)
for node_fn in [assess_tier, retrieve_context, call_tools, generate_response]:
    builder.add_node(node_fn.__name__, node_fn)
builder.set_entry_point("assess_tier")
builder.add_edge("assess_tier",      "retrieve_context")
builder.add_edge("retrieve_context", "call_tools")
builder.add_edge("call_tools",       "generate_response")
builder.add_edge("generate_response", END)
graph = builder.compile()

DEGRADATION_NOTICES = {
    ServiceTier.FULL:    "",
    ServiceTier.REDUCED: "[Limited mode: real-time data and tool calls unavailable — answering from knowledge only]",
    ServiceTier.MINIMAL: "[Service temporarily unavailable — please try again in a few minutes]",
}

def add_degradation_notice(state: AgentState) -> dict:
    notice = DEGRADATION_NOTICES.get(ServiceTier[state["tier"]], "")
    if notice:
        return {"response": f"{notice}\n\n{state['response']}"}
    return {}

def health_check() -> dict:
    tier = current_tier(breakers)
    breaker_states = {
        name: cb.state.name
        for name, cb in breakers.items()
    }
    return {
        "status": "ok" if tier == ServiceTier.FULL else "degraded",
        "tier":   tier.name,
        "features": {
            k: v for k, v in vars(TIER_FLAGS[tier]).items()
        },
        "breakers": breaker_states,
    }

# Response when REDUCED:
# {
#   "status": "degraded",
#   "tier": "REDUCED",
#   "features": {"llm_completions": true, "tool_calls": false, ...},
#   "breakers": {"completions": "CLOSED", "tool_calls": "OPEN", ...}
# }

def full_recovery_chain(query: str, tier: ServiceTier) -> str:
    flags = TIER_FLAGS[tier]

    # Attempt 1: full RAG + LLM with retries
    if flags.rag_retrieval and flags.llm_completions:
        try:
            context = retry_with_backoff(
                lambda: protected_vector_search(query), max_attempts=2, base_delay=0.5
            )
            return retry_with_backoff(
                lambda: protected_completion(f"{query}\nContext: {context}"), max_attempts=3
            )
        except Exception:
            pass   # fall through to next tier

    # Attempt 2: LLM only, no RAG
    if flags.llm_completions:
        try:
            return retry_with_backoff(
                lambda: protected_completion(query), max_attempts=2, base_delay=1.0
            )
        except Exception:
            pass

    # Final: static
    return DEGRADATION_NOTICES[ServiceTier.MINIMAL]
